# 커스텀 CSS (디자인 유지 및 텍스트 중앙 정렬 추가)
# ══════════════════════════════════════════════════════════════════════════
st.markdown("""
<style>
@import url('https://fonts.googleapis.com/css2?family=Noto+Sans+KR:wght@300;400;500;700;900&family=Bebas+Neue&display=swap');
:root {
    --col-lightest: #f1e3f3; --col-lavender: #c2bbf0; --col-sky: #8fb8ed;
    --col-bright: #62bfed; --col-main: #3590f3; --col-dark: #2a6dc4;
    --col-text: #2c2c54; --col-subtext: #5a5a8a;
}
html, body, [class*="css"] { font-family: 'Noto Sans KR', sans-serif; }
.gu-header { background: linear-gradient(135deg, var(--col-main) 0%, var(--col-sky) 60%, var(--col-lavender) 100%); border-radius: 16px; padding: 25px; color: white; margin-bottom: 12px; text-align: center; }
.metric-card { 
    border-radius: 12px; padding: 15px; border-left: 4px solid var(--col-main); 
    background: linear-gradient(135deg, var(--col-lightest), #e8dcf5);
    text-align: center; /* 텍스트 가운데 정렬 추가 */
}
.metric-card.green { background: linear-gradient(135deg, #dff0fb, #c2e8f7); border-left-color: var(--col-bright); }
.metric-card.orange { background: linear-gradient(135deg, var(--col-lightest), #e8dcf5); border-left-color: var(--col-lavender); }
.metric-card.purple { background: linear-gradient(135deg, #e8eeff, #d4e4fb); border-left-color: var(--col-sky); }
.metric-card .mlabel { font-size:0.75rem; color:var(--col-subtext); font-weight:700; margin-bottom:5px; }
.metric-card .mvalue { font-size:1.4rem; font-weight:900; color:var(--col-text); line-height:1.2; }
.metric-card .msub { font-size:0.7rem; color:var(--col-subtext); margin-top:5px; line-height:1.4; }
.mcomp { display: inline-block; margin-top: 8px; padding: 3px 10px; border-radius: 20px; font-size: 0.7rem; font-weight: 700; }
.mcomp.better { background:#dff0fb; color:#1a6a9a; }
.mcomp.worse { background:#fde8e8; color:#c0392b; }
.mcomp.neutral { background:#ede8f8; color:var(--col-subtext); }
</style>
""", unsafe_allow_html=True)

